$((function(){"use strict";$(document).on("click",".a-fileupload-delete",(function(){$(this).parent().parent().hide();var fileId=$(this).closest("tr").find("td:eq(0)").find("input:eq(0)").val();if(fileId==""){$(this).closest("tr").find("td:eq(0)").find("input:eq(3)").attr("value","Cancelled")}else{$(this).closest("tr").find("td:eq(0)").find("input:eq(3)").attr("value","Deleted")}return false}));$(document).on("click","#fileupload",(function(){$("#progress .progress-bar").css("width",0+"%")}));var url="/FileUpload/PurchaseOrderAttachment/Index";$("#fileupload").fileupload({url:url,pasteZone:null,acceptFileTypes:/(jpg)|(jpeg)|(png)|(gif)|(pdf)|(txt)|(xls)|(xlsx)|(doc)|(docx)$/i,dataType:"json",done:function(e,data){var html="";$.each(data.result,(function(index,file){html+="<tr>";html+="   <td><div class='dv-attachment-name'>"+file.OriginalFileName+"</div>";html+="       <input type='hidden' name='PurchaseOrder.PurchaseOrderAttachments[0].Id' class='fld-fileupload-id' />";html+="       <input type='hidden' name='PurchaseOrder.PurchaseOrderAttachments[0].OriginalFileName' class='fld-fileupload-original-filename' value='"+file.OriginalFileName+"' />";html+="       <input type='hidden' name='PurchaseOrder.PurchaseOrderAttachments[0].FileName' class='fld-fileupload-filename' value='"+file.FileName+"' />";html+="       <input type='hidden' name='PurchaseOrder.PurchaseOrderAttachments[0].Tag' class='fld-fileupload-tag' value='"+file.Tag+"' />";html+="       <input type='hidden' name='PurchaseOrder.PurchaseOrderAttachments[0].PurchaseOrderId' class='fld-fileupload-purchaseorder-id' />";html+="   </td>";html+="   <td>"+file.UploaderName;html+="       <input type='hidden' name='PurchaseOrder.PurchaseOrderAttachments[0].UploaderId' value='"+file.UploaderId+"' class='fld-fileuploader-id' />";html+="       <input type='hidden' name='PurchaseOrder.PurchaseOrderAttachments[0].UploaderName' value='"+file.UploaderName+"' class='fld-fileuploader-name' />";html+="   </td>";html+="   <td>"+moment().format("MMM DD, YYYY");html+="       <input type='hidden' name='PurchaseOrder.PurchaseOrderAttachments[0].CreatedAt' value='"+moment().format("MMM DD, YYYY")+"' class='fld-fileupload-createdat' />";html+="   </td>";html+="   <td><div class='pull-right'>";html+="       <a href='#' class='btn btn-default a-fileupload-delete'  data-toggle='tooltip' title='Delete'><span class='fa fa-trash' ></span></a>";html+="       <a href='/Content/files/attachments/"+file.FileName+"' class='btn btn-default a-fileupload-view' download='"+file.OriginalFileName+"'target='_blank' data-toggle='tooltip' title='Download'><i class='fa fa-download' aria-hidden='true'></i></a>";html+="   </div></td>";html+="</tr>"}));$("#tbd-fileupload").append(html);resetNameCollection(".fld-fileupload-id","PurchaseOrder.PurchaseOrderAttachments","Id");resetNameCollection(".fld-fileupload-purchaseorder-id","PurchaseOrder.PurchaseOrderAttachments","PurchaseOrderId");resetNameCollection(".fld-fileupload-original-filename","PurchaseOrder.PurchaseOrderAttachments","OriginalFileName");resetNameCollection(".fld-fileupload-filename","PurchaseOrder.PurchaseOrderAttachments","FileName");resetNameCollection(".fld-fileupload-tag","PurchaseOrder.PurchaseOrderAttachments","Tag");resetNameCollection(".fld-fileuploader-id","PurchaseOrder.PurchaseOrderAttachments","UploaderId");resetNameCollection(".fld-fileuploader-name","PurchaseOrder.PurchaseOrderAttachments","UploaderName")},progressall:function(e,data){var progress=parseInt(data.loaded/data.total*100,10);$("#progress .progress-bar").css("width",progress+"%")}}).prop("disabled",!$.support.fileInput).parent().addClass($.support.fileInput?undefined:"disabled")}));